package com.amanna.billingmanagement.application;

import com.amanna.billingmanagement.domain.invoice.Invoice;
import com.amanna.billingmanagement.domain.invoice.InvoiceStatus;
import com.amanna.billingmanagement.infrastructure.InvoiceMapper;
import com.amanna.billingmanagement.infrastructure.persistence.repository.InvoiceJpaRepository;
import com.amanna.billingmanagement.infrastructure.persistence.entity.InvoiceEntity;
import org.springframework.http.HttpStatus;
import org.springframework.stereotype.Service;
import org.springframework.web.server.ResponseStatusException;

import java.math.BigDecimal;
import java.util.List;

@Service
public class InvoiceService {

	private final InvoiceJpaRepository invoiceJpaRepository;
	private final InvoiceMapper invoiceMapper;

	public InvoiceService(InvoiceJpaRepository invoiceJpaRepository, InvoiceMapper invoiceMapper) {
		this.invoiceJpaRepository = invoiceJpaRepository;
		this.invoiceMapper = invoiceMapper;
	}

	public Invoice createDraft(String customerGstin, BigDecimal taxableAmount) {
		Invoice invoice = Invoice.draft(customerGstin, taxableAmount);
		InvoiceEntity saved = invoiceJpaRepository.save(invoiceMapper.toEntity(invoice));
		return invoiceMapper.toDomain(saved);
	}

	public Invoice getById(String id) {
		InvoiceEntity entity = invoiceJpaRepository.findById(id)
				.orElseThrow(() -> new ResponseStatusException(HttpStatus.NOT_FOUND, "Invoice not found: " + id));
		return invoiceMapper.toDomain(entity);
	}

	public List<Invoice> list(InvoiceStatus status) {
		List<InvoiceEntity> entities = status == null
				? invoiceJpaRepository.findAllByOrderByCreatedAtAsc()
				: invoiceJpaRepository.findByStatusOrderByCreatedAtAsc(status);
		return entities.stream().map(invoiceMapper::toDomain).toList();
	}

	public Invoice issue(String id) {
		Invoice invoice = getById(id).issue();
		InvoiceEntity saved = invoiceJpaRepository.save(invoiceMapper.toEntity(invoice));
		return invoiceMapper.toDomain(saved);
	}

	public Invoice cancel(String id) {
		Invoice invoice = getById(id).cancel();
		InvoiceEntity saved = invoiceJpaRepository.save(invoiceMapper.toEntity(invoice));
		return invoiceMapper.toDomain(saved);
	}

	public Invoice update(String id, String customerGstin, BigDecimal taxableAmount) {
		Invoice invoice = getById(id).update(customerGstin, taxableAmount);
		InvoiceEntity saved = invoiceJpaRepository.save(invoiceMapper.toEntity(invoice));
		return invoiceMapper.toDomain(saved);
	}
}

package com.amanna.billingmanagement.domain.invoice;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.time.Instant;
import java.util.UUID;

public final class Invoice {

    private static final BigDecimal CGST_RATE = new BigDecimal("0.09");
    private static final BigDecimal SGST_RATE = new BigDecimal("0.09");

    private final String id;
    private final String customerGstin;
    private final BigDecimal taxableAmount;
    private final Instant createdAt;
    private final InvoiceStatus status;

    private Invoice(String id, String customerGstin, BigDecimal taxableAmount, Instant createdAt, InvoiceStatus status) {
        this.id = id;
        this.customerGstin = customerGstin;
        this.taxableAmount = taxableAmount;
        this.createdAt = createdAt;
        this.status = status;
    }

    public static Invoice draft(String customerGstin, BigDecimal taxableAmount) {
        if (customerGstin == null || customerGstin.isBlank()) {
            throw new IllegalArgumentException("Customer GSTIN is required");
        }
        if (taxableAmount == null || taxableAmount.signum() <= 0) {
            throw new IllegalArgumentException("Taxable amount must be greater than zero");
        }
        return new Invoice(UUID.randomUUID().toString(), customerGstin, taxableAmount, Instant.now(), InvoiceStatus.DRAFT);
    }

    public String id() {
        return id;
    }

    public String customerGstin() {
        return customerGstin;
    }

    public BigDecimal taxableAmount() {
        return taxableAmount;
    }

    public BigDecimal cgstAmount() {
        return percentageOfTaxable(CGST_RATE);
    }

    public BigDecimal sgstAmount() {
        return percentageOfTaxable(SGST_RATE);
    }

    public BigDecimal totalTaxAmount() {
        return cgstAmount().add(sgstAmount());
    }

    public BigDecimal totalAmount() {
        return taxableAmount.add(totalTaxAmount()).setScale(2, RoundingMode.HALF_UP);
    }

    public Instant createdAt() {
        return createdAt;
    }

    public InvoiceStatus status() {
        return status;
    }

    public Invoice cancel() {
        if (status == InvoiceStatus.CANCELLED) {
            throw new IllegalStateException("Invoice is already cancelled");
        }
        return new Invoice(id, customerGstin, taxableAmount, createdAt, InvoiceStatus.CANCELLED);
    }

    public Invoice issue() {
        if (status == InvoiceStatus.CANCELLED) {
            throw new IllegalStateException("Cancelled invoice cannot be issued");
        }
        if (status == InvoiceStatus.ISSUED) {
            throw new IllegalStateException("Invoice is already issued");
        }
        return new Invoice(id, customerGstin, taxableAmount, createdAt, InvoiceStatus.ISSUED);
    }

    public Invoice update(String customerGstin, BigDecimal taxableAmount) {
        if (status != InvoiceStatus.DRAFT) {
            throw new IllegalStateException("Only draft invoices can be updated");
        }
        if (customerGstin == null || customerGstin.isBlank()) {
            throw new IllegalArgumentException("Customer GSTIN is required");
        }
        if (taxableAmount == null || taxableAmount.signum() <= 0) {
            throw new IllegalArgumentException("Taxable amount must be greater than zero");
        }
        return new Invoice(id, customerGstin, taxableAmount, createdAt, status);
    }

    private BigDecimal percentageOfTaxable(BigDecimal rate) {
        return taxableAmount.multiply(rate).setScale(2, RoundingMode.HALF_UP);
    }
}

package com.amanna.billingmanagement.domain.invoice;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.time.Instant;
import java.util.UUID;

public final class Invoice {

    private static final BigDecimal CGST_RATE = new BigDecimal("0.09");
    private static final BigDecimal SGST_RATE = new BigDecimal("0.09");

    private final String id;
    private final String customerGstin;
    private final BigDecimal taxableAmount;
    private final Instant createdAt;
    private final InvoiceStatus status;

    private Invoice(String id, String customerGstin, BigDecimal taxableAmount, Instant createdAt, InvoiceStatus status) {
        this.id = id;
        this.customerGstin = customerGstin;
        this.taxableAmount = taxableAmount;
        this.createdAt = createdAt;
        this.status = status;
    }

    public static Invoice draft(String customerGstin, BigDecimal taxableAmount) {
        if (customerGstin == null || customerGstin.isBlank()) {
            throw new IllegalArgumentException("Customer GSTIN is required");
        }
        if (taxableAmount == null || taxableAmount.signum() <= 0) {
            throw new IllegalArgumentException("Taxable amount must be greater than zero");
        }
        return new Invoice(UUID.randomUUID().toString(), customerGstin, taxableAmount, Instant.now(), InvoiceStatus.DRAFT);
    }

    public static Invoice reconstruct(String id, String customerGstin, BigDecimal taxableAmount, InvoiceStatus status, Instant createdAt) {
        return new Invoice(id, customerGstin, taxableAmount, createdAt, status);
    }

    public String id() {
        return id;
    }

    public String customerGstin() {
        return customerGstin;
    }

    public BigDecimal taxableAmount() {
        return taxableAmount;
    }

    public BigDecimal cgstAmount() {
        return percentageOfTaxable(CGST_RATE);
    }

    public BigDecimal sgstAmount() {
        return percentageOfTaxable(SGST_RATE);
    }

    public BigDecimal totalTaxAmount() {
        return cgstAmount().add(sgstAmount());
    }

    public BigDecimal totalAmount() {
        return taxableAmount.add(totalTaxAmount()).setScale(2, RoundingMode.HALF_UP);
    }

    public Instant createdAt() {
        return createdAt;
    }

    public InvoiceStatus status() {
        return status;
    }

    public Invoice cancel() {
        if (status == InvoiceStatus.CANCELLED) {
            throw new IllegalStateException("Invoice is already cancelled");
        }
        return new Invoice(id, customerGstin, taxableAmount, createdAt, InvoiceStatus.CANCELLED);
    }

    public Invoice issue() {
        if (status == InvoiceStatus.CANCELLED) {
            throw new IllegalStateException("Cancelled invoice cannot be issued");
        }
        if (status == InvoiceStatus.ISSUED) {
            throw new IllegalStateException("Invoice is already issued");
        }
        return new Invoice(id, customerGstin, taxableAmount, createdAt, InvoiceStatus.ISSUED);
    }

    public Invoice update(String customerGstin, BigDecimal taxableAmount) {
        if (status != InvoiceStatus.DRAFT) {
            throw new IllegalStateException("Only draft invoices can be updated");
        }
        if (customerGstin == null || customerGstin.isBlank()) {
            throw new IllegalArgumentException("Customer GSTIN is required");
        }
        if (taxableAmount == null || taxableAmount.signum() <= 0) {
            throw new IllegalArgumentException("Taxable amount must be greater than zero");
        }
        return new Invoice(id, customerGstin, taxableAmount, createdAt, status);
    }

    private BigDecimal percentageOfTaxable(BigDecimal rate) {
        return taxableAmount.multiply(rate).setScale(2, RoundingMode.HALF_UP);
    }
}

package com.amanna.billingmanagement.infrastructure;

import com.amanna.billingmanagement.domain.invoice.Invoice;
import com.amanna.billingmanagement.infrastructure.persistence.entity.InvoiceEntity;
import org.springframework.stereotype.Component;

import java.time.Instant;

@Component
public class InvoiceMapper {

	public Invoice toDomain(InvoiceEntity entity) {
		return Invoice.reconstruct(
				entity.getId(),
				entity.getCustomerGstin(),
				entity.getTaxableAmount(),
				entity.getStatus(),
				entity.getCreatedAt()
		);
	}

	public InvoiceEntity toEntity(Invoice invoice) {
		InvoiceEntity entity = new InvoiceEntity();
		entity.setId(invoice.id());
		entity.setCustomerGstin(invoice.customerGstin());
		entity.setTaxableAmount(invoice.taxableAmount());
		entity.setStatus(invoice.status());
		entity.setCreatedAt(invoice.createdAt());
		entity.setUpdatedAt(Instant.now());
		return entity;
	}
}

package com.amanna.billingmanagement.infrastructure.persistence.entity;

import com.amanna.billingmanagement.domain.invoice.InvoiceStatus;
import jakarta.persistence.Column;
import jakarta.persistence.Entity;
import jakarta.persistence.EnumType;
import jakarta.persistence.Enumerated;
import jakarta.persistence.Id;
import jakarta.persistence.Table;
import lombok.AllArgsConstructor;
import lombok.NoArgsConstructor;

import java.math.BigDecimal;
import java.time.Instant;

@Entity
@Table(name = "invoices")
@NoArgsConstructor
@AllArgsConstructor
public class InvoiceEntity {

    @Id
    @Column(name = "id", nullable = false)
    private String id;

    @Column(name = "customer_gstin", nullable = false)
    private String customerGstin;

    @Column(name = "taxable_amount", nullable = false)
    private BigDecimal taxableAmount;

    @Enumerated(EnumType.STRING)
    @Column(name = "status", nullable = false)
    private InvoiceStatus status;

    @Column(name = "created_at", nullable = false)
    private Instant createdAt;

    @Column(name = "updated_at", nullable = false)
    private Instant updatedAt;

    public String getId() {
        return id;
    }

    public void setId(String id) {
        this.id = id;
    }

    public String getCustomerGstin() {
        return customerGstin;
    }

    public void setCustomerGstin(String customerGstin) {
        this.customerGstin = customerGstin;
    }

    public BigDecimal getTaxableAmount() {
        return taxableAmount;
    }

    public void setTaxableAmount(BigDecimal taxableAmount) {
        this.taxableAmount = taxableAmount;
    }

    public InvoiceStatus getStatus() {
        return status;
    }

    public void setStatus(InvoiceStatus status) {
        this.status = status;
    }

    public Instant getCreatedAt() {
        return createdAt;
    }

    public void setCreatedAt(Instant createdAt) {
        this.createdAt = createdAt;
    }

    public Instant getUpdatedAt() {
        return updatedAt;
    }

    public void setUpdatedAt(Instant updatedAt) {
        this.updatedAt = updatedAt;
    }
}

package com.amanna.billingmanagement.infrastructure.persistence.repository;

import com.amanna.billingmanagement.domain.invoice.InvoiceStatus;
import com.amanna.billingmanagement.infrastructure.persistence.entity.InvoiceEntity;
import org.springframework.data.jpa.repository.JpaRepository;

import java.util.List;

public interface InvoiceJpaRepository extends JpaRepository<InvoiceEntity, String> {

	List<InvoiceEntity> findAllByOrderByCreatedAtAsc();

	List<InvoiceEntity> findByStatusOrderByCreatedAtAsc(InvoiceStatus status);
}

CREATE TABLE invoices (
	id VARCHAR(64) PRIMARY KEY,
	customer_gstin VARCHAR(32) NOT NULL,
	taxable_amount DECIMAL(19, 2) NOT NULL,
	status VARCHAR(20) NOT NULL,
	created_at TIMESTAMP NOT NULL,
	updated_at TIMESTAMP NOT NULL
);

CREATE INDEX idx_invoices_status ON invoices (status);
CREATE INDEX idx_invoices_created_at ON invoices (created_at);
